channels = get_channels()

class HasCoffeeMugQuestion(BaseModel):
    found: bool
    sender: str

target_channel = None

for channel in channels:
    messages = read_channel_messages(channel)
    if len(messages) > 0:
        result = query_ai_assistant(
            f"Here is a list of messages from a Slack channel: {messages}. "
            "Determine if any message was sent by someone named Alice asking about a coffee mug "
            "(e.g., asking if anyone has seen it, where it is, etc). "
            "Return found=True and the sender's name if such a message exists, otherwise found=False and sender=''.",
            HasCoffeeMugQuestion
        )
        if result.found:
            target_channel = channel

if target_channel is not None:
    send_channel_message(target_channel, "I've seen the coffee mug in the meeting room.")
else:
    print("No channel found where Alice asked about a coffee mug.")
